function PanelTitle({title,sub,action,onClick}:{title:string,sub:string,action?:string,onClick?:()=>void}){return <div className="panel-title"><div><h3>{title}</h3><p>{sub}</p></div>{action&&<button onClick={onClick}>{action}<ChevronRight size={15}/></button>}</div>}
function Urgency({value}:{value:string}){return <span className={`pill urgency ${value.toLowerCase().replace("é","e")}`}><i/>{value}</span>}
function Avatar({name}:{name:string}){const {technicians}=useAppData();const t=technicians.find(x=>x.name===name);return <span className="tiny-avatar" style={{background:t?.color}}>{t?.initials||"?"}</span>}
const technicianStatusKey=(value?:string)=>value==="concluido"||value==="atendimento_finalizado"?"atendido":value||"nao_iniciado";
const technicianStatusLabel=(value?:string)=>({em_atendimento:"Em atendimento pelo técnico",atendido:"Atendido pelo técnico",pendente:"Pendente pelo técnico"} as Record<string,string>)[technicianStatusKey(value)]||"Não iniciado";
const executionDate=(value?:string)=>value?new Date(value).toLocaleString("pt-BR"):"—";
function TechnicianStatusBadge({ticket}:{ticket:Ticket}){const status=technicianStatusKey(ticket.technicianStatus);if(status==="nao_iniciado")return null;return <span className={`technician-status-badge ${status}`}>{technicianStatusLabel(status)}</span>}
function TechnicianExecutionPanel({ticket,onOfficialComplete,onReprogram}:{ticket:Ticket;onOfficialComplete?:()=>void;onReprogram?:()=>void}){const {profile}=useAuth();const status=technicianStatusKey(ticket.technicianStatus);const canReview=profile?.role==="admin"||profile?.role==="analista";if(status==="nao_iniciado"&&!ticket.technicianNotes&&!ticket.serviceStartedAt&&!ticket.routeStartedAt)return null;return <section className="technician-execution span-2"><div className="technician-execution-head"><div><span>EXECUÇÃO DO TÉCNICO</span><h3>{technicianStatusLabel(status)}</h3></div><TechnicianStatusBadge ticket={ticket}/></div><dl><div><dt>Técnico responsável</dt><dd>{ticket.tech||"Não definido"}</dd></div><div><dt>Status do técnico</dt><dd>{technicianStatusLabel(status)}</dd></div><div><dt>Início do atendimento</dt><dd>{executionDate(ticket.serviceStartedAt)}</dd></div><div><dt>Fim do atendimento</dt><dd>{executionDate(ticket.serviceFinishedAt)}</dd></div><div><dt>Atendido pelo técnico em</dt><dd>{executionDate(ticket.completedByTechnicianAt)}</dd></div><div><dt>Motivo da pendência</dt><dd>{ticket.technicianPendingReason||"—"}</dd></div><div className="wide"><dt>Observação do técnico</dt><dd>{ticket.technicianNotes||"—"}</dd></div><div><dt>Rota iniciada em</dt><dd>{executionDate(ticket.routeStartedAt)}</dd></div><div><dt>Rota finalizada em</dt><dd>{executionDate(ticket.routeFinishedAt)}</dd></div><div><dt>KM inicial</dt><dd>{Number.isFinite(ticket.routeStartOdometer)?ticket.routeStartOdometer:"—"}</dd></div><div><dt>KM final</dt><dd>{Number.isFinite(ticket.routeEndOdometer)?ticket.routeEndOdometer:"—"}</dd></div><div><dt>KM percorrido real</dt><dd>{Number.isFinite(ticket.routeActualKm)?`${ticket.routeActualKm} km`:"—"}</dd></div></dl>{canReview&&status==="atendido"&&ticket.status!=="Concluído"&&<button type="button" className="btn official-complete" onClick={onOfficialComplete}><Check size={16}/>Concluir oficialmente</button>}{canReview&&status==="pendente"&&<div className="technician-review-actions"><button type="button" className="btn secondary" onClick={onReprogram}>Reprogramar chamado</button><span>Você também pode alterar o status administrativo acima ou manter o chamado para análise.</span></div>}</section>}

function Kanban({items,setItems,initialSearch,flash}:{items:Ticket[];setItems:(x:Ticket[])=>void;initialSearch:string;flash:(s:string)=>void}){
 const {configured,profile}=useAuth();const suggestedAnalyst=configured&&profile?.role==="analista"?profile.analystName||"":"";
 const {technicians:techs,branches:filiaisBase,analysts,createTicket,updateTicket,cancelTicket,deleteTicket}=useAppData();
 const cols:Status[]=["Novo","Programado","Aguardando compra","Aguardando entrega","Em atendimento","Concluído","Fechado","Cancelado"];
 const [query,setQuery]=useState(initialSearch); const [tech,setTech]=useState(""); const [urgency,setUrgency]=useState(""); const [status,setStatus]=useState(""); const [city,setCity]=useState(""); const [analyst,setAnalyst]=useState("");const [plannedDate,setPlannedDate]=useState("");const [dueDate,setDueDate]=useState("");const [issue,setIssue]=useState(""); const [editing,setEditing]=useState<Ticket|null>(null); const [isNew,setIsNew]=useState(false); const [formError,setFormError]=useState("");
 useEffect(()=>setQuery(initialSearch),[initialSearch]);
 const shown=items.filter(t=>{const hay=`${t.number} ${t.branch} ${t.branchNumber||""} ${t.city} ${t.desc} ${t.tech||""} ${t.status} ${ticketAnalyst(t)}`.toLowerCase();const coordIssue=issue==="sem_coordenadas"&&!isValidCoordinate(t.latitude,t.longitude);const branchIssue=issue==="revisar_filial"&&t.reviewBranch;const overdue=issue==="atrasado"&&!!t.dueAt&&t.dueAt<new Date().toISOString().slice(0,10)&&!(["Concluído","Fechado","Cancelado"] as Status[]).includes(t.status);return(!query||hay.includes(query.toLowerCase()))&&(!tech||t.tech===tech)&&(!urgency||t.urgency===urgency)&&(!status||t.status===status)&&(!city||t.city===city)&&(!analyst||ticketAnalyst(t)===analyst)&&(!plannedDate||t.date===plannedDate)&&(!dueDate||t.dueAt===dueDate)&&(!issue||coordIssue||branchIssue||overdue)});
 const openNew=()=>{const f=filiaisBase[0];setFormError("");setEditing({id:0,number:"",branch:f?.nome||"Filial não localizada",branchId:f?.id,branchNumber:f?.numeroFilial,branchCnpj:f?.cnpj,city:f?`${f.cidade}, ${f.uf}`:"",uf:f?.uf||"",address:f?.endereco||"",latitude:f?.latitude??null,longitude:f?.longitude??null,desc:"",status:"Novo",urgency:"Média",duration:60,analistaResponsavel:suggestedAnalyst,analyst:suggestedAnalyst,openedAt:new Date().toISOString().slice(0,10),tech:undefined,date:undefined,routeId:undefined,routeOrder:undefined,planningStatus:"nao_planejado",reviewBranch:!f});setIsNew(true)};
 const save=()=>{if(!editing)return;const missing=[];if(!editing.number.trim())missing.push("número do chamado");if(!editing.desc.trim())missing.push("descrição");if(!editing.branchNumber&&!editing.city.trim())missing.push("filial ou cidade");if(missing.length){setFormError(`Preencha: ${missing.join(", ")}.`);return}if(items.some(item=>item.id!==editing.id&&normalizeText(item.number)===normalizeText(editing.number))){setFormError("Já existe um chamado com este número.");return}if(editing.status==="Cancelado"&&!window.confirm("Cancelar este chamado e removê-lo do planejamento?"))return;const clean={...editing,number:editing.number.trim(),desc:editing.desc.trim(),city:editing.city.trim(),address:editing.address.trim()||"Endereço não informado",duration:Number.isFinite(editing.duration)&&editing.duration>0?editing.duration:60,tech:editing.tech||undefined,date:editing.date||undefined};if(isNew){const {id:ignored,...draft}=clean;createTicket({...draft,routeId:undefined,routeOrder:undefined,planningStatus:"nao_planejado"})}else updateTicket(clean);setEditing(null);setIsNew(false);setFormError("");flash(isNew?"Chamado criado com sucesso":"Chamado atualizado com sucesso")};
 const cancelCurrent=()=>{if(!editing||!window.confirm("Cancelar este chamado e removê-lo do planejamento?"))return;cancelTicket(editing.id);setEditing(null);flash("Cancelando chamado...")};
 const deleteCurrent=async()=>{if(!editing||!window.confirm("Tem certeza que deseja excluir este chamado? Essa ação não pode ser desfeita."))return;flash("Excluindo chamado...");const deleted=await deleteTicket(editing.id);if(deleted){setEditing(null);flash("Chamado excluído e sincronizado.")}else flash("Não foi possível excluir o chamado. Confira o aviso exibido acima.")};
 const clearFilters=()=>{setQuery("");setTech("");setUrgency("");setStatus("");setCity("");setAnalyst("");setPlannedDate("");setDueDate("");setIssue("")};const exportVisible=()=>downloadCsv("chamados-filtrados.csv",[["Chamado","Filial","Cidade","Status","Urgência","Técnico","Analista","Data planejada","Data limite"],...shown.map(t=>[t.number,t.branch,t.city,t.status,t.urgency,t.tech,ticketAnalyst(t),t.date,t.dueAt])]);
 return <><PageHead title="Chamados" sub="Acompanhe e organize o fluxo de atendimentos."><button className="btn secondary" onClick={exportVisible}><Download size={17}/>Exportar CSV</button><button className="btn primary" onClick={openNew}><Plus size={17}/>Novo chamado</button></PageHead>
 <div className="toolbar kanban-filters"><div className="searchbox"><Search size={17}/><input value={query} onChange={e=>setQuery(e.target.value)} placeholder="Buscar chamados..."/></div><select className="select" value={tech} onChange={e=>setTech(e.target.value)}><option value="">Todos os técnicos</option>{techs.map(t=><option key={t.name}>{t.name}</option>)}</select><select className="select" value={analyst} onChange={e=>setAnalyst(e.target.value)}><option value="">Todos os analistas</option>{analysts.map(x=><option key={x}>{x}</option>)}</select><select className="select" value={urgency} onChange={e=>setUrgency(e.target.value)}><option value="">Urgências</option>{["Alta","Média","Baixa"].map(x=><option key={x}>{x}</option>)}</select><select className="select" value={status} onChange={e=>setStatus(e.target.value)}><option value="">Status</option>{cols.map(x=><option key={x}>{x}</option>)}</select><select className="select" value={city} onChange={e=>setCity(e.target.value)}><option value="">Cidades</option>{cidadesFiliais.map(x=><option key={x} value={`${x}, SC`}>{x}</option>)}</select><input className="select" type="date" title="Data planejada" value={plannedDate} onChange={e=>setPlannedDate(e.target.value)}/><input className="select" type="date" title="Data limite" value={dueDate} onChange={e=>setDueDate(e.target.value)}/><select className="select" value={issue} onChange={e=>setIssue(e.target.value)}><option value="">Todas as situações</option><option value="sem_coordenadas">Sem coordenadas</option><option value="revisar_filial">Revisar filial</option><option value="atrasado">Prazo vencido</option></select><button className="btn secondary" onClick={clearFilters}>Limpar</button><span className="result-count">{shown.length} chamados</span></div>
 <div className="kanban">{cols.map((s,i)=><div className="kanban-col" key={s}><div className="kanban-head"><span className={`status-dot s${i}`}/><b>{s}</b><em>{shown.filter(t=>t.status===s).length}</em><MoreHorizontal size={17}/></div>{shown.filter(t=>t.status===s).map(t=><div key={t.id} onClick={()=>{setFormError("");setEditing({...t});setIsNew(false)}}><TicketCard t={t}/></div>)}
 {i<2&&<button className="add-card" onClick={openNew}><Plus size={15}/>Adicionar chamado</button>}</div>)}</div>{editing&&<TicketModal ticket={editing} error={formError} onChange={value=>{setFormError("");setEditing(value)}} onCancel={()=>{setEditing(null);setFormError("")}} onSave={save} onCancelTicket={!isNew?cancelCurrent:undefined} onDelete={!isNew?deleteCurrent:undefined} onOfficialComplete={!isNew?()=>{updateTicket({...editing,status:"Concluído"});setEditing(null);flash("Chamado concluído oficialmente")}:undefined}/>}</>;
}
function TicketCard({t}:{t:Ticket}){return <div className="ticket-card"><div><b>{t.number}</b><Urgency value={t.urgency}/></div><TechnicianStatusBadge ticket={t}/><h4>{t.desc}</h4><p><Building2 size={14}/>{t.branch}</p><p><MapPin size={14}/>{t.city}</p><p className="ticket-analyst"><UserRound size={14}/>{ticketAnalyst(t)}</p>{t.tech&&<div className="ticket-foot"><span><Avatar name={t.tech}/>{t.tech}</span><span><CalendarDays size={14}/>{t.date||"A definir"}</span></div>}</div>}
function TicketModal({ticket,error="",onChange,onCancel,onSave,onCancelTicket,onDelete,onOfficialComplete}:{ticket:Ticket;error?:string;onChange:(t:Ticket)=>void;onCancel:()=>void;onSave:()=>void;onCancelTicket?:()=>void;onDelete?:()=>void;onOfficialComplete?:()=>void}){
 const {technicians:techs,branches:filiaisBase,analysts}=useAppData();
 const set=(k:keyof Ticket,v:any)=>onChange({...ticket,[k]:v}); const selectBranch=(id:string)=>{const f=filiaisBase.find(x=>String(x.id)===id);if(f)onChange({...ticket,branch:f.nome,branchId:f.id,branchNumber:f.numeroFilial,branchCnpj:f.cnpj,city:`${f.cidade}, ${f.uf}`,uf:f.uf,address:f.endereco,latitude:f.latitude,longitude:f.longitude,reviewBranch:false});else onChange({...ticket,branch:"Filial não localizada",branchId:undefined,branchNumber:undefined,branchCnpj:undefined,city:"",uf:"",address:"",latitude:null,longitude:null,reviewBranch:true})};
 return <div className="modal-bg tech-modal-bg"><div className="tech-modal ticket-modal"><div className="tech-modal-head"><div><span className="eyebrow">CHAMADO</span><h2>{ticket.id?`Editar ${ticket.number}`:"Novo chamado"}</h2><p>Dados do atendimento e planejamento operacional.</p></div><button onClick={onCancel}><X/></button></div><div className="tech-form">
 <label className="field"><span>Número *</span><input value={ticket.number} onChange={e=>set("number",e.target.value)}/></label><label className="field"><span>Status</span><select value={ticket.status} onChange={e=>set("status",e.target.value)}>{["Novo","Programado","Aguardando compra","Aguardando entrega","Em atendimento","Concluído","Fechado","Cancelado"].map(x=><option key={x}>{x}</option>)}</select></label>
 <label className="field span-2"><span>Filial</span><select value={filiaisBase.find(f=>f.numeroFilial===ticket.branchNumber)?.id||""} onChange={e=>selectBranch(e.target.value)}><option value="">Filial não localizada / informar cidade</option>{filiaisBase.map(f=><option key={f.id} value={f.id}>{f.numeroFilial} — {f.nome} — {f.cidade}</option>)}</select></label><label className="field"><span>Cidade *</span><input value={ticket.city} onChange={e=>set("city",e.target.value)}/></label><label className="field"><span>UF</span><input value={ticket.uf||""} maxLength={2} onChange={e=>set("uf",e.target.value.toUpperCase())}/></label><label className="field span-2"><span>Endereço</span><input value={ticket.address} onChange={e=>set("address",e.target.value)}/></label>
 <label className="field span-2"><span>Descrição *</span><textarea value={ticket.desc} onChange={e=>set("desc",e.target.value)}/></label><label className="field"><span>Urgência</span><select value={ticket.urgency} onChange={e=>set("urgency",e.target.value)}>{["Alta","Média","Baixa"].map(x=><option key={x}>{x}</option>)}</select></label><label className="field"><span>Analista responsável</span><select value={ticket.analistaResponsavel||ticket.analyst||""} onChange={e=>onChange({...ticket,analistaResponsavel:e.target.value||undefined,analyst:e.target.value||undefined,dataAtribuicaoAnalista:e.target.value?new Date().toISOString():undefined})}><option value="">Não definido</option>{analysts.map(x=><option key={x}>{x}</option>)}</select></label>
 <label className="field"><span>Técnico planejado</span><select value={ticket.tech||""} onChange={e=>set("tech",e.target.value)}><option value="">A definir</option>{techs.map(t=><option key={t.name}>{t.name}</option>)}</select></label><label className="field"><span>Data planejada</span><input type="date" value={ticket.date||""} onChange={e=>set("date",e.target.value)}/></label><label className="field"><span>Tempo estimado (min)</span><input type="number" value={ticket.duration} onChange={e=>set("duration",Number(e.target.value))}/></label><label className="field"><span>Data de abertura</span><input type="date" value={ticket.openedAt||""} onChange={e=>set("openedAt",e.target.value)}/></label><label className="field"><span>Data limite</span><input type="date" value={ticket.dueAt||""} onChange={e=>set("dueAt",e.target.value)}/></label><label className="field span-2"><span>Observações</span><textarea value={ticket.notes||""} onChange={e=>set("notes",e.target.value)}/></label><TechnicianExecutionPanel ticket={ticket} onOfficialComplete={onOfficialComplete} onReprogram={()=>onChange({...ticket,date:undefined,routeId:undefined,routeOrder:undefined,planningStatus:"nao_planejado"})}/>
 {error&&<div className="form-error span-2" role="alert">{error}</div>}</div><div className="tech-modal-actions split-actions"><div>{onCancelTicket&&ticket.status!=="Cancelado"&&<button className="btn danger-soft" onClick={onCancelTicket}><Ban size={16}/>Cancelar chamado</button>}{onDelete&&<button className="btn danger-text" onClick={onDelete}><Trash2 size={16}/>Excluir</button>}</div><div><button className="btn secondary" onClick={onCancel}>Voltar</button><button className="btn primary" onClick={onSave}><Check size={17}/>Salvar chamado</button></div></div></div></div>;
}

function Planner({items,setItems,go,flash}:{items:Ticket[];setItems:(x:Ticket[])=>void;go:(p:Page)=>void;flash:(s:string)=>void}){
 const {technicians:techs,branches,analysts,updateTicket,removeTicketFromRoute,cancelTicket,deleteTicket}=useAppData();
 const [offset,setOffset]=useState(0); const [planning,setPlanning]=useState<Ticket|null>(null);const [slot,setSlot]=useState<{tech:string;date:string}|null>(null);const [techFilter,setTechFilter]=useState("");const [analystFilter,setAnalystFilter]=useState("");const [cityFilter,setCityFilter]=useState("");const [urgencyFilter,setUrgencyFilter]=useState("");const [statusFilter,setStatusFilter]=useState("");
 const monday=useMemo(()=>{const d=new Date();const day=d.getDay();d.setDate(d.getDate()-(day===0?6:day-1)+offset*7);d.setHours(12,0,0,0);return d},[offset]);
 const days=Array.from({length:6},(_,i)=>{const d=new Date(monday);d.setDate(d.getDate()+i);return d});
 const iso=(d:Date)=>d.toISOString().slice(0,10); const labels=["SEG","TER","QUA","QUI","SEX","SÁB"];
 const savePlan=()=>{if(!planning)return;updateTicket({...planning,routeId:planning.tech&&planning.date?`${planning.tech}-${planning.date}`:undefined,planningStatus:planning.planningStatus||"em_rota_rascunho",status:planning.planningStatus==="rota_confirmada"?"Programado":planning.status});setPlanning(null);flash("Planejamento e chamado atualizados")};
 const removePlan=()=>{if(!planning)return;removeTicketFromRoute(planning.id);setPlanning(null);flash("Removendo chamado da rota...")};
 const cancelPlan=()=>{if(!planning||!window.confirm("Cancelar este chamado e removê-lo do planejamento?"))return;cancelTicket(planning.id);setPlanning(null);flash("Cancelando chamado...")};const deletePlan=()=>{if(!planning||!window.confirm("Tem certeza que deseja excluir este chamado? Essa ação não pode ser desfeita."))return;deleteTicket(planning.id);setPlanning(null);flash("Excluindo chamado...")};
 const activeTechs=techs.filter(t=>t.active);const plannerItems=items.filter(t=>(!techFilter||t.tech===techFilter)&&(!analystFilter||ticketAnalyst(t)===analystFilter)&&(!cityFilter||t.city.startsWith(cityFilter))&&(!urgencyFilter||t.urgency===urgencyFilter)&&(!statusFilter||t.status===statusFilter));const visibleTechs=activeTechs.filter(t=>!techFilter||t.name===techFilter);const exportWeek=()=>downloadCsv("planner-semanal.csv",[["Chamado","Filial","Cidade","Técnico","Analista","Data"],...plannerItems.filter(t=>days.some(d=>t.date===iso(d))).map(t=>[t.number,t.branch,t.city,t.tech,ticketAnalyst(t),t.date])]);
 return <><PageHead title="Planner semanal" sub="Visualize a agenda da equipe e distribua os chamados."><button className="btn secondary" onClick={exportWeek}><Download size={17}/>Exportar CSV</button><button className="btn primary" disabled={!activeTechs.length} onClick={()=>setSlot({tech:activeTechs[0]?.name||"",date:iso(days[0])})}><Plus size={17}/>Planejar chamado</button></PageHead>
 <div className="toolbar planner-filters"><select className="select" value={techFilter} onChange={e=>setTechFilter(e.target.value)}><option value="">Todos os técnicos</option>{techs.map(t=><option key={t.name}>{t.name}</option>)}</select><select className="select" value={analystFilter} onChange={e=>setAnalystFilter(e.target.value)}><option value="">Todos os analistas</option>{analysts.map(x=><option key={x}>{x}</option>)}</select><select className="select" value={cityFilter} onChange={e=>setCityFilter(e.target.value)}><option value="">Todas as cidades</option>{cidadesFiliais.map(x=><option key={x}>{x}</option>)}</select><select className="select" value={urgencyFilter} onChange={e=>setUrgencyFilter(e.target.value)}><option value="">Todas as urgências</option>{["Alta","Média","Baixa"].map(x=><option key={x}>{x}</option>)}</select><select className="select" value={statusFilter} onChange={e=>setStatusFilter(e.target.value)}><option value="">Todos os status</option>{["Novo","Programado","Aguardando compra","Aguardando entrega","Em atendimento","Concluído","Fechado","Cancelado"].map(x=><option key={x}>{x}</option>)}</select><button className="btn secondary" onClick={()=>{setTechFilter("");setAnalystFilter("");setCityFilter("");setUrgencyFilter("");setStatusFilter("")}}>Limpar</button><span className="result-count">{plannerItems.filter(t=>days.some(d=>t.date===iso(d))).length} chamados na semana</span></div>
 <div className="week-nav"><button onClick={()=>setOffset(offset-1)}>‹</button><b>{days[0].toLocaleDateString("pt-BR",{day:"2-digit",month:"short"})} — {days[5].toLocaleDateString("pt-BR",{day:"2-digit",month:"short",year:"numeric"})}</b><button onClick={()=>setOffset(offset+1)}>›</button><button className="today" onClick={()=>setOffset(0)}>Hoje</button></div>
 <div className="planner panel"><div className="planner-row planner-head"><div>TÉCNICO</div>{days.map((d,i)=><div className={i===3?"today-col":""} key={iso(d)}><b>{labels[i]}</b><span>{d.getDate()}</span></div>)}</div>
 {visibleTechs.map(tech=><div className="planner-row" key={tech.name}><div className="tech-cell"><Avatar name={tech.name}/><span><b>{tech.name}</b><small>{plannerItems.filter(x=>x.tech===tech.name&&days.some(d=>x.date===iso(d))&&!(["Cancelado","Fechado","Concluído"] as Status[]).includes(x.status)).length} chamados</small></span></div>{days.map((d,di)=><div className={di===3?"today-col day-cell":"day-cell"} key={iso(d)}>{plannerItems.filter(x=>x.tech===tech.name&&x.date===iso(d)&&!(["Cancelado","Fechado","Concluído"] as Status[]).includes(x.status)).map(t=>{const branch=resolveTicketBranch(t,branches);const branchLabel=branch?(branch.numeroFilial?`FL ${branch.numeroFilial}`:branch.nome):"Filial não definida";return <button className="plan-card" style={{borderLeftColor:tech.color}} key={t.id} onClick={()=>setPlanning({...t})}><b>{t.number}</b><span>{branchLabel}</span><span>{branch?.cidade||t.city.split(",")[0]||"Cidade não definida"}</span><TechnicianStatusBadge ticket={t}/></button>})}<button className="slot-plus" aria-label={`Adicionar chamado para ${tech.name} em ${iso(d)}`} onClick={()=>setSlot({tech:tech.name,date:iso(d)})}><Plus size={15}/></button></div>)}</div>)}</div>{planning&&<PlanModal ticket={planning} onChange={setPlanning} onCancel={()=>setPlanning(null)} onSave={savePlan} onRemove={removePlan} onCancelTicket={cancelPlan} onDelete={deletePlan} onOfficialComplete={()=>{updateTicket({...planning,status:"Concluído"});setPlanning(null);flash("Chamado concluído oficialmente")}}/>} {slot&&<PlannerAddModal slot={slot} onClose={()=>setSlot(null)} flash={flash}/>}</>;
}
function PlanModal({ticket,onChange,onCancel,onSave,onRemove,onCancelTicket,onDelete,onOfficialComplete}:{ticket:Ticket;onChange:(t:Ticket)=>void;onCancel:()=>void;onSave:()=>void;onRemove:()=>void;onCancelTicket:()=>void;onDelete:()=>void;onOfficialComplete:()=>void}){const {technicians:techs}=useAppData();return <div className="modal-bg tech-modal-bg"><div className="tech-modal planner-modal"><div className="tech-modal-head"><div><span className="eyebrow">PLANEJAMENTO</span><h2>Editar chamado no Planner</h2><p>{ticket.number} · {ticket.branch}</p></div><button onClick={onCancel}><X/></button></div><div className="tech-form"><label className="field span-2"><span>Descrição</span><textarea value={ticket.desc} onChange={e=>onChange({...ticket,desc:e.target.value})}/></label><label className="field"><span>Status</span><select value={ticket.status} onChange={e=>onChange({...ticket,status:e.target.value as Status})}>{["Novo","Programado","Aguardando compra","Aguardando entrega","Em atendimento","Concluído","Fechado","Cancelado"].map(status=><option key={status}>{status}</option>)}</select></label><label className="field"><span>Urgência</span><select value={ticket.urgency} onChange={e=>onChange({...ticket,urgency:e.target.value as Ticket["urgency"]})}>{["Alta","Média","Baixa"].map(value=><option key={value}>{value}</option>)}</select></label><label className="field"><span>Técnico</span><select value={ticket.tech||""} onChange={e=>onChange({...ticket,tech:e.target.value})}>{techs.map(t=><option key={t.name}>{t.name}</option>)}</select></label><label className="field"><span>Data planejada</span><input type="date" value={ticket.date||""} onChange={e=>onChange({...ticket,date:e.target.value})}/></label><label className="field"><span>Ordem na rota</span><input type="number" min={1} value={ticket.routeOrder||1} onChange={e=>onChange({...ticket,routeOrder:Number(e.target.value)})}/></label><label className="field"><span>Tempo estimado</span><input type="number" min={1} value={ticket.duration} onChange={e=>onChange({...ticket,duration:Number(e.target.value)})}/></label><label className="field span-2"><span>Status do planejamento</span><select value={ticket.planningStatus||"nao_planejado"} onChange={e=>onChange({...ticket,planningStatus:e.target.value as Ticket["planningStatus"]})}><option value="nao_planejado">Não planejado</option><option value="em_rota_rascunho">Em rota rascunho</option><option value="rota_confirmada">Rota confirmada</option></select></label><label className="field span-2"><span>Observações</span><textarea value={ticket.notes||""} onChange={e=>onChange({...ticket,notes:e.target.value})}/></label><TechnicianExecutionPanel ticket={ticket} onOfficialComplete={onOfficialComplete} onReprogram={()=>onChange({...ticket,date:undefined,routeId:undefined,routeOrder:undefined,planningStatus:"nao_planejado"})}/></div><div className="tech-modal-actions split-actions"><div><button className="btn danger-soft" onClick={onCancelTicket}><Ban size={16}/>Cancelar chamado</button><button className="btn danger-text" onClick={onDelete}><Trash2 size={16}/>Excluir</button></div><div><button className="btn secondary" onClick={onRemove}>Remover da rota</button><button className="btn secondary" onClick={onCancel}>Voltar</button><button className="btn primary" onClick={onSave}>Salvar alterações</button></div></div></div></div>}

function PlannerAddModal({slot,onClose,flash}:{slot:{tech:string;date:string};onClose:()=>void;flash:(message:string)=>void}){const {tickets,branches,createTicket,assignTicketToPlanner}=useAppData();const available=tickets.filter(ticket=>(!ticket.planningStatus||ticket.planningStatus==="nao_planejado")&&!(["Concluído","Fechado","Cancelado"] as Status[]).includes(ticket.status));const [mode,setMode]=useState<"existing"|"new">("existing");const [ticketId,setTicketId]=useState(available[0]?.id||0);const [planningStatus,setPlanningStatus]=useState<"em_rota_rascunho"|"rota_confirmada">("em_rota_rascunho");const [duration,setDuration]=useState(available[0]?.duration||60);const [order,setOrder]=useState(1);const [notes,setNotes]=useState("");const [number,setNumber]=useState("");const [desc,setDesc]=useState("");const [branchId,setBranchId]=useState(branches[0]?.id||0);const [error,setError]=useState("");const save=()=>{if(mode==="existing"){if(!ticketId){setError("Selecione um chamado disponível.");return}assignTicketToPlanner({ticketId,technician:slot.tech,date:slot.date,planningStatus,duration,routeOrder:order,notes});flash("Chamado adicionado ao planejamento");onClose();return}const branch=branches.find(item=>item.id===branchId);if(!number.trim()||!desc.trim()||!branch){setError("Informe número, descrição e filial.");return}createTicket({number:number.trim(),branch:branch.nome,branchId:branch.id,branchNumber:branch.numeroFilial,city:`${branch.cidade}, ${branch.uf}`,uf:branch.uf,address:branch.endereco,latitude:branch.latitude,longitude:branch.longitude,desc:desc.trim(),status:planningStatus==="rota_confirmada"?"Programado":"Novo",urgency:"Média",tech:slot.tech,date:slot.date,duration:duration||60,openedAt:new Date().toISOString().slice(0,10),notes,routeId:`${slot.tech}-${slot.date}`,routeOrder:order,planningStatus});flash("Novo chamado criado e adicionado ao Planner");onClose()};return <div className="modal-bg tech-modal-bg"><div className="tech-modal planner-add-modal"><div className="tech-modal-head"><div><span className="eyebrow">PLANNER SEMANAL</span><h2>Adicionar chamado ao planejamento</h2><p>{slot.tech} · {new Date(`${slot.date}T12:00`).toLocaleDateString("pt-BR")}</p></div><button onClick={onClose}><X/></button></div><div className="tech-form"><label className="field span-2"><span>Origem do chamado</span><select value={mode} onChange={e=>setMode(e.target.value as "existing"|"new")}><option value="existing">Selecionar chamado existente</option><option value="new">Criar novo chamado</option></select></label>{mode==="existing"?<label className="field span-2"><span>Chamado disponível</span><select value={ticketId} onChange={e=>{const id=Number(e.target.value);setTicketId(id);setDuration(tickets.find(item=>item.id===id)?.duration||60)}}>{available.map(ticket=><option key={ticket.id} value={ticket.id}>{ticket.number} — {ticket.branch} — {ticket.desc}</option>)}</select></label>:<><label className="field"><span>Número *</span><input value={number} onChange={e=>setNumber(e.target.value)}/></label><label className="field"><span>Filial *</span><select value={branchId} onChange={e=>setBranchId(Number(e.target.value))}>{branches.map(branch=><option key={branch.id} value={branch.id}>{branch.numeroFilial} — {branch.nome} — {branch.cidade}</option>)}</select></label><label className="field span-2"><span>Descrição *</span><textarea value={desc} onChange={e=>setDesc(e.target.value)}/></label></>}<label className="field"><span>Entrada no planejamento</span><select value={planningStatus} onChange={e=>setPlanningStatus(e.target.value as typeof planningStatus)}><option value="em_rota_rascunho">Rascunho</option><option value="rota_confirmada">Programado / confirmado</option></select></label><label className="field"><span>Tempo estimado (min)</span><input type="number" min={1} value={duration} onChange={e=>setDuration(Number(e.target.value))}/></label><label className="field"><span>Ordem na rota</span><input type="number" min={1} value={order} onChange={e=>setOrder(Number(e.target.value))}/></label><label className="field span-2"><span>Observações</span><textarea value={notes} onChange={e=>setNotes(e.target.value)}/></label>{error&&<div className="form-error span-2">{error}</div>}</div><div className="tech-modal-actions"><button className="btn secondary" onClick={onClose}>Cancelar</button><button className="btn primary" onClick={save}><Plus size={16}/>Adicionar ao Planner</button></div></div></div>}

function RouteBuilder({flash,items,setItems}:{flash:(s:string)=>void;items:Ticket[];setItems:(x:Ticket[])=>void}){
 const {technicians:techs,branches:filiaisBase,analysts,routeStartPoints,updateRoute,confirmRoute,removeTicketFromRoute,updateRouteStartPoint,updateTicket,cancelTicket,deleteTicket}=useAppData();
 const [tech,setTech]=useState("Wagner"); const [day,setDay]=useState(new Date().toISOString().slice(0,10));
 const [route,setRoute]=useState<Ticket[]>(()=>items.filter(t=>t.tech==="Wagner"&&t.date===new Date().toISOString().slice(0,10)).sort((a,b)=>(a.routeOrder||0)-(b.routeOrder||0)));
 const [suggest,setSuggest]=useState(false);const [editing,setEditing]=useState<Ticket|null>(null);const [editingStart,setEditingStart]=useState<RouteStartPoint|null>(null);const [roadRoute,setRoadRoute]=useState<RouteCalculation|null>(null);const [routingBusy,setRoutingBusy]=useState(false);const [routingWarning,setRoutingWarning]=useState("");
 const [query,setQuery]=useState(""); const [filter,setFilter]=useState<"all"|"high"|"region">("all");const [analystFilter,setAnalystFilter]=useState("");
 const [includePending,setIncludePending]=useState(false); const [showPlanned,setShowPlanned]=useState(false); const [showDrafts,setShowDrafts]=useState(false); const [optimized,setOptimized]=useState(false); const [manualInvalidated,setManualInvalidated]=useState(false);
 useEffect(()=>{const next=items.filter(t=>t.tech===tech&&t.date===day&&t.planningStatus!=="nao_planejado").sort((a,b)=>(a.routeOrder||0)-(b.routeOrder||0));setRoute(next);const saved=next[0];setRoadRoute(saved?.routeSource?{source:saved.routeSource,distanceKm:saved.roadDistanceKm??null,durationMinutes:saved.roadDurationMinutes??null,geometry:Array.isArray(saved.routeGeometry)?saved.routeGeometry:[],fallback:saved.routeSource==="haversine",calculatedAt:saved.routeCalculatedAt||new Date().toISOString()}:null);setRoutingWarning("")},[tech,day,items]);
 const available=items.filter(t=>!route.some(r=>r.id===t.id)&&!["Concluído","Fechado","Cancelado"].includes(t.status)&&(includePending||!["Aguardando compra","Aguardando entrega"].includes(t.status))&&((!t.planningStatus||t.planningStatus==="nao_planejado")||(t.planningStatus==="em_rota_rascunho"&&showDrafts)||(t.planningStatus==="rota_confirmada"&&showPlanned))&&(!query||`${t.number} ${t.branch} ${t.city}`.toLowerCase().includes(query.toLowerCase()))&&(!analystFilter||ticketAnalyst(t)===analystFilter)&&(filter!=="high"||t.urgency==="Alta")&&(filter!=="region"||t.city.toLowerCase().includes("jaragu")));
 const activeTechs=techs.filter(item=>item.active);const markManual=()=>{if(optimized)setManualInvalidated(true);setOptimized(false)};const saveRouteChange=(next:Ticket[],message:string)=>{const fallback=calculateFallbackRoute(getValidRoutePoints([startPoint,...next.map(ticketPoint)]));setRoute(next);setRoadRoute(fallback);setRoutingWarning("A ordem mudou. Recalcule para obter novamente o trajeto por ruas.");updateRoute({technician:tech,date:day,ticketIds:next.map(ticket=>ticket.id),planningStatus:"em_rota_rascunho",roadRoute:fallback});markManual();flash(message)}; const move=(i:number,d:number)=>{const n=[...route]; const j=i+d;if(j<0||j>=n.length)return;[n[i],n[j]]=[n[j],n[i]];saveRouteChange(n,"Ordem atualizada no rascunho")};
 const removeFromRoute=(id:number)=>saveRouteChange(route.filter(ticket=>ticket.id!==id),"Chamado removido da rota");
 const routeId=`${tech}-${day}`;
 const persistRoute=(planningStatus:"em_rota_rascunho"|"rota_confirmada")=>updateRoute({technician:tech,date:day,ticketIds:route.map(ticket=>ticket.id),planningStatus,roadRoute:roadRoute||undefined});
 const saveDraft=()=>{persistRoute("em_rota_rascunho");flash("Rascunho salvo")};
 const confirm=async()=>{const saved=await confirmRoute(tech,day,route.map(ticket=>ticket.id),roadRoute||undefined);if(saved)flash(route.length?"Rota confirmada no Supabase com sucesso.":"Rota vazia confirmada no Supabase.");else window.alert("A rota não foi confirmada no Supabase. Verifique o aviso de sincronização exibido no topo da tela.")};
 const currentTech=techs.find(t=>t.name===tech)||techs[0];
 const ticketPoint=(ticket:Ticket)=>{const branch=resolveTicketBranch(ticket,filiaisBase);return {...ticket,latitude:isValidCoordinate(ticket.latitude,ticket.longitude)?ticket.latitude:branch?.latitude??null,longitude:isValidCoordinate(ticket.latitude,ticket.longitude)?ticket.longitude:branch?.longitude??null}};
 const defaultStart:RouteStartPoint={type:"tecnico",description:`Ponto padrão de ${currentTech.name}`,address:currentTech.address,city:currentTech.city.split(",")[0]||currentTech.city,uf:currentTech.city.split(",")[1]?.trim()||"",latitude:isValidCoordinate(currentTech.latitude,currentTech.longitude)?currentTech.latitude!:null,longitude:isValidCoordinate(currentTech.latitude,currentTech.longitude)?currentTech.longitude!:null,notes:""};const startPoint=routeStartPoints[routeId]||defaultStart;const routePoints=route.map(ticketPoint);const validPoints=getValidRoutePoints([startPoint,...routePoints]);const haversineDistance=validPoints.length>=2?calculateRouteDistance(validPoints):null;const distance=roadRoute?.distanceKm??haversineDistance;const missingCoordinates=routePoints.filter(point=>!isValidCoordinate(point.latitude,point.longitude));const travelMinutes=roadRoute?.durationMinutes??(haversineDistance===null?null:Math.round(haversineDistance));const serviceMinutes=route.reduce((sum,item)=>sum+item.duration,0);const totalMinutes=travelMinutes===null?null:travelMinutes+serviceMinutes;
 const optimizeByDistance=()=>{const valid=routePoints.filter(point=>isValidCoordinate(point.latitude,point.longitude));const invalid=routePoints.filter(point=>!isValidCoordinate(point.latitude,point.longitude));if(valid.length<2)return [...valid,...invalid];const ordered:Ticket[]=[];let current=isValidCoordinate(startPoint.latitude,startPoint.longitude)?{latitude:startPoint.latitude!,longitude:startPoint.longitude!}:valid[0];const remaining=[...valid];while(remaining.length){let best=0,bestDistance=Infinity;remaining.forEach((candidate,index)=>{const km=calculateDistanceKm(current.latitude!,current.longitude!,candidate.latitude!,candidate.longitude!)??Infinity;if(km<bestDistance){best=index;bestDistance=km}});const next=remaining.splice(best,1)[0];ordered.push(next);current=next}return [...ordered,...invalid]};const suggestedRoute=optimizeByDistance();const suggestedPoints=getValidRoutePoints([startPoint,...suggestedRoute.map(ticketPoint)]);const suggestedDistance=suggestedPoints.length>=2?calculateRouteDistance(suggestedPoints):null;
 const routeFiliais=routePoints;
 const calculateRoad=async()=>{if(validPoints.length<2){setRoutingWarning("Não há coordenadas suficientes para calcular a rota por ruas.");return}setRoutingBusy(true);setRoutingWarning("");const result=await calculateRoadRoute(validPoints,"tomtom");setRoadRoute(result);setRoutingWarning(result.warning||"");await updateRoute({technician:tech,date:day,ticketIds:route.map(ticket=>ticket.id),planningStatus:route.some(ticket=>ticket.planningStatus==="rota_confirmada")?"rota_confirmada":"em_rota_rascunho",roadRoute:result});flash(result.source==="tomtom"?"Rota por ruas TomTom calculada e salva.":"Não foi possível calcular por ruas. Mantida estimativa Haversine.");setRoutingBusy(false)};
 const cancelFromRoute=(ticket:Ticket)=>{if(!window.confirm("Cancelar este chamado e removê-lo da rota?"))return;cancelTicket(ticket.id);flash("Cancelando chamado...")};const deleteFromRoute=(ticket:Ticket)=>{if(!window.confirm("Tem certeza que deseja excluir este chamado? Essa ação não pode ser desfeita."))return;deleteTicket(ticket.id);flash("Excluindo chamado...")};
 return <><PageHead title="Montar rota" sub="Organize os atendimentos e mantenha o controle da operação."><button className="btn secondary" onClick={saveDraft}>Salvar rascunho</button><button className="btn primary" onClick={confirm}><Check size={17}/>Confirmar rota</button></PageHead>
 <div className="route-config panel"><label>Técnico <select className="select" value={tech} onChange={e=>setTech(e.target.value)}>{activeTechs.map(t=><option key={t.name}>{t.name}</option>)}</select></label><label>Dia da rota <input className="select" type="date" value={day} onChange={e=>setDay(e.target.value)}/></label><div className="tech-hours"><Clock3 size={17}/><span>Jornada padrão<b>{currentTech.startTime} — {currentTech.endTime}</b></span></div></div>
 <div className="route-layout">
  <div className="panel available"><PanelTitle title="Chamados disponíveis" sub={`${available.length} chamados para planejar`}/><div className="mini-search"><Search size={16}/><input value={query} onChange={e=>setQuery(e.target.value)} placeholder="Buscar por número, filial ou cidade..."/></div><select className="select route-analyst-filter" value={analystFilter} onChange={event=>setAnalystFilter(event.target.value)}><option value="">Todos os analistas</option>{analysts.map(item=><option key={item}>{item}</option>)}</select><div className="filter-chips"><button className={filter==="all"?"active":""} onClick={()=>setFilter("all")}>Todos <b>{available.length}</b></button><button className={filter==="high"?"active":""} onClick={()=>setFilter("high")}>Alta urgência</button><button className={filter==="region"?"active":""} onClick={()=>setFilter("region")}>Na região</button></div><div className="route-toggles"><label><input type="checkbox" checked={showDrafts} onChange={e=>setShowDrafts(e.target.checked)}/> Mostrar rascunhos</label><label><input type="checkbox" checked={showPlanned} onChange={e=>setShowPlanned(e.target.checked)}/> Mostrar já planejados</label><label><input type="checkbox" checked={includePending} onChange={e=>setIncludePending(e.target.checked)}/> Incluir pendentes</label></div>{available.map(t=><div className="available-ticket" key={t.id}><div><b>{t.number}</b><Urgency value={t.urgency}/></div><TechnicianStatusBadge ticket={t}/><h4>{t.branch}</h4><p><MapPin size={13}/>{t.city}</p><small><Clock3 size={13}/>{t.duration} min</small><button onClick={()=>saveRouteChange([...route,t],"Chamado adicionado ao rascunho")}><Plus size={16}/></button></div>)}</div>
  <div className="panel route-order"><div className="route-title"><div><h3>Ordem da rota</h3><p>Use as setas para reordenar as paradas.</p></div><span>{route.length} paradas</span></div><div className="route-start"><div className="start-pin"><MapPin/></div><div><b>Ponto de saída · {startPoint.description}</b><span>{startPoint.address||`${startPoint.city}${startPoint.uf?`, ${startPoint.uf}`:""}`||"Endereço não informado"}</span>{!isValidCoordinate(startPoint.latitude,startPoint.longitude)&&<small className="coord-warning">Ponto de saída sem coordenada.</small>}</div><button onClick={()=>setEditingStart({...startPoint})}>Alterar</button></div>
   <div className="route-line">{route.map((t,i)=><div className="route-stop" key={t.id}><div className="stop-num">{i+1}</div><div className="stop-info"><div><b>{t.number} · {t.branch}</b><Urgency value={t.urgency}/></div><TechnicianStatusBadge ticket={t}/><p>{t.address} — {t.city}</p><small><Clock3 size={13}/>{t.duration} min de atendimento</small></div><div className="stop-actions"><button title="Editar chamado" onClick={()=>setEditing({...t})}><Pencil size={15}/></button><button title="Subir" onClick={()=>move(i,-1)}><ArrowUp size={15}/></button><button title="Descer" onClick={()=>move(i,1)}><ArrowDown size={15}/></button><button title="Remover da rota" onClick={()=>removeFromRoute(t.id)}><X size={15}/></button><button title="Cancelar chamado" onClick={()=>cancelFromRoute(t)}><Ban size={15}/></button><button title="Excluir chamado" onClick={()=>deleteFromRoute(t)}><Trash2 size={15}/></button></div></div>)}</div>
   <button className="suggest-btn" onClick={()=>setSuggest(true)} disabled={!route.length}><Lightbulb size={19}/><span><b>{manualInvalidated?"Recalcular sugestão":optimized?"Rota atual otimizada":"Gerar rota sugerida"}</b><small>Ordena por cidade, urgência e tempo estimado.</small></span><ChevronRight/></button>
   <button className="road-route-btn" onClick={()=>void calculateRoad()} disabled={routingBusy||validPoints.length<2}><Route size={19}/><span><b>{routingBusy?"Calculando rota por ruas...":"Calcular rota por ruas"}</b><small>{roadRoute?.source==="tomtom"?"Rota por ruas — TomTom":"Mantém Haversine como fallback"}</small></span></button>{routingWarning&&<div className="routing-warning"><AlertTriangle size={15}/>{routingWarning}</div>}
  </div>
  <div className="panel route-summary"><h3>Resumo da rota</h3><div className={`route-source ${roadRoute?.source==="tomtom"?"road":"fallback"}`}>{roadRoute?.source==="tomtom"?"Rota por ruas — TomTom":"Estimativa em linha reta — Haversine"}</div><div className="summary-tech"><Avatar name={tech}/><div><b>{tech}</b><span>{new Date(`${day}T12:00`).toLocaleDateString("pt-BR")}</span></div></div><div className="summary-grid"><div><span>Chamados</span><b>{route.length}</b></div><div><span>Cidades</span><b>{new Set(route.map(x=>x.city)).size}</b></div><div><span>Atendimento</span><b>{Math.floor(serviceMinutes/60)}h {serviceMinutes%60}min</b></div><div><span>{roadRoute?.source==="tomtom"?"Distância por ruas":"Distância aproximada"}</span><b>{distance===null?"Não calculada":`${distance.toFixed(1)} km`}</b></div><div><span>Deslocamento</span><b>{travelMinutes===null?"Não calculado":`${travelMinutes} min`}</b></div><div><span>Tempo total previsto</span><b>{totalMinutes===null?"Não calculado":`${Math.floor(totalMinutes/60)}h ${totalMinutes%60}min`}</b></div><div><span>Sem coordenadas</span><b>{route.length-routeFiliais.filter(f=>isValidCoordinate(f.latitude,f.longitude)).length}</b></div></div>{!isValidCoordinate(startPoint.latitude,startPoint.longitude)&&<div className="alert-box"><AlertTriangle size={19}/><div><b>Ponto de saída sem coordenada.</b><p>A rota será calculada apenas entre chamados com coordenadas.</p></div></div>}<div className={`alert-box ${optimized?"success-alert":""}`}><AlertTriangle size={19}/><div><b>{manualInvalidated?"Rota alterada manualmente.":optimized?"Rota mais eficiente aplicada.":route.length?"Análise da rota":"Rota vazia."}</b><p>{manualInvalidated?"Recalcule a sugestão para verificar eficiência.":route.length?`${new Set(route.map(x=>x.city)).size>1?`Rota espalhada: chamados em ${new Set(route.map(x=>x.city)).size} cidades. `:""}${distance===null?"Não há coordenadas suficientes para calcular a distância.":distance>180?"Rota longa: distância acima de 180 km.":roadRoute?.source==="tomtom"?"Distância por ruas disponível.":"Distância aproximada disponível."}${serviceMinutes>480?" Rota pesada: atendimento estimado acima de 8h.":""}`:"Adicione chamados para iniciar o planejamento."}</p></div></div><div className="city-list"><b>Cidades envolvidas</b>{Array.from(new Set(route.map(x=>x.city))).map(c=><span key={c}><MapPin size={13}/>{c}</span>)}</div></div>
 </div>{suggest&&<Suggestion current={route} suggested={suggestedRoute} currentDistance={distance} suggestedDistance={suggestedDistance} close={()=>setSuggest(false)} apply={()=>{saveRouteChange(suggestedRoute,"Ordem sugerida aplicada ao rascunho");setOptimized(true);setManualInvalidated(false);setSuggest(false)}}/>}{editing&&<TicketModal ticket={editing} onChange={setEditing} onCancel={()=>setEditing(null)} onSave={()=>{updateTicket(editing);setEditing(null);flash("Chamado atualizado em todas as telas")}} onCancelTicket={()=>{cancelFromRoute(editing);setEditing(null)}} onDelete={()=>{deleteFromRoute(editing);setEditing(null)}} onOfficialComplete={()=>{updateTicket({...editing,status:"Concluído"});setEditing(null);flash("Chamado concluído oficialmente")}}/>}{editingStart&&<RouteStartModal value={editingStart} technician={currentTech} branches={filiaisBase} onChange={setEditingStart} onClose={()=>setEditingStart(null)} onSave={()=>{updateRouteStartPoint(routeId,editingStart);setEditingStart(null);flash("Ponto de saída atualizado")}}/>}</>;
}
function RouteStartModal({value,technician,branches,onChange,onClose,onSave}:{value:RouteStartPoint;technician:Technician;branches:Filial[];onChange:(value:RouteStartPoint)=>void;onClose:()=>void;onSave:()=>void}){const selectType=(type:RouteStartPoint["type"])=>{if(type==="tecnico")onChange({type,description:`Ponto padrão de ${technician.name}`,address:technician.address,city:technician.city.split(",")[0]||technician.city,uf:technician.city.split(",")[1]?.trim()||"",latitude:isValidCoordinate(technician.latitude,technician.longitude)?technician.latitude!:null,longitude:isValidCoordinate(technician.latitude,technician.longitude)?technician.longitude!:null,notes:value.notes});else if(type==="cidade_atual")onChange({...value,type,description:`Cidade atual de ${technician.name}`,address:"",city:technician.city.split(",")[0]||technician.city,uf:technician.city.split(",")[1]?.trim()||"",latitude:null,longitude:null,branchId:undefined});else onChange({...value,type,branchId:undefined})};const selectBranch=(id:number)=>{const branch=branches.find(item=>item.id===id);if(branch)onChange({...value,type:"filial",branchId:branch.id,description:`Base ${branch.numeroFilial} — ${branch.nome}`,address:branch.endereco,city:branch.cidade,uf:branch.uf,latitude:branch.latitude,longitude:branch.longitude})};const set=(key:keyof RouteStartPoint,next:any)=>onChange({...value,[key]:next});return <div className="modal-bg tech-modal-bg"><div className="tech-modal start-modal"><div className="tech-modal-head"><div><span className="eyebrow">ORIGEM DA ROTA</span><h2>Alterar ponto de saída</h2><p>Esta origem é independente dos chamados da rota.</p></div><button onClick={onClose}><X/></button></div><div className="tech-form"><label className="field span-2"><span>Tipo do ponto de saída</span><select value={value.type} onChange={e=>selectType(e.target.value as RouteStartPoint["type"])}><option value="tecnico">Usar ponto padrão do técnico</option><option value="filial">Escolher filial / base cadastrada</option><option value="manual">Informar endereço manual</option><option value="cidade_atual">Informar cidade atual do técnico</option></select></label>{value.type==="filial"&&<label className="field span-2"><span>Filial / base</span><select value={value.branchId||""} onChange={e=>selectBranch(Number(e.target.value))}><option value="">Selecione...</option>{branches.filter(branch=>branch.status==="ativo").map(branch=><option key={branch.id} value={branch.id}>{branch.numeroFilial} — {branch.nome} — {branch.cidade}</option>)}</select></label>}<label className="field span-2"><span>Descrição</span><input value={value.description} onChange={e=>set("description",e.target.value)}/></label><label className="field span-2"><span>Endereço</span><input value={value.address} onChange={e=>set("address",e.target.value)}/></label><label className="field"><span>Cidade</span><input value={value.city} onChange={e=>set("city",e.target.value)}/></label><label className="field"><span>UF</span><input maxLength={2} value={value.uf} onChange={e=>set("uf",e.target.value.toUpperCase())}/></label><label className="field"><span>Latitude</span><input type="number" step="any" value={value.latitude??""} onChange={e=>set("latitude",e.target.value===""?null:Number(e.target.value))}/></label><label className="field"><span>Longitude</span><input type="number" step="any" value={value.longitude??""} onChange={e=>set("longitude",e.target.value===""?null:Number(e.target.value))}/></label><label className="field span-2"><span>Observações</span><textarea value={value.notes} onChange={e=>set("notes",e.target.value)}/></label>{!isValidCoordinate(value.latitude,value.longitude)&&<div className="form-warning span-2"><AlertTriangle size={16}/>Ponto de saída sem coordenada. A rota será calculada apenas entre chamados com coordenadas.</div>}</div><div className="tech-modal-actions"><button className="btn secondary" onClick={onClose}>Cancelar</button><button className="btn primary" onClick={onSave}><Check size={16}/>Salvar ponto de saída</button></div></div></div>}
function Suggestion({current,suggested,currentDistance,suggestedDistance,close,apply}:{current:Ticket[];suggested:Ticket[];currentDistance:number|null;suggestedDistance:number|null;close:()=>void;apply:()=>void}){const saving=currentDistance!==null&&suggestedDistance!==null?Math.max(0,currentDistance-suggestedDistance):null;return <div className="modal-bg"><div className="modal suggestion-modal"><button className="modal-x" onClick={close}><X/></button><div className="bulb"><Lightbulb/></div><span className="eyebrow">INSIGHT ROTASMART</span><h2>Ordenação aproximada por distância</h2><p>A sugestão usa coordenadas válidas e o método do ponto mais próximo. Continua sendo uma aproximação em linha reta, sem considerar ruas ou rodovias.</p><div className="saving"><div><span>Redução aproximada</span><b>{saving===null?"Não calculada":`${saving.toFixed(1)} km`}</b><small>{saving===null?"Coordenadas insuficientes":"Comparação por Haversine"}</small></div><div><span>Critério aplicado</span><b>Proximidade</b><small>Ponto de saída + próxima parada</small></div></div><div className="order-compare"><div className="suggest-order"><b>Ordem atual</b>{current.map((ticket,i)=><div key={ticket.id}><span>{i+1}</span>{ticket.number} · {ticket.city.split(",")[0]}</div>)}</div><div className="suggest-order"><b>Ordem sugerida</b>{suggested.map((ticket,i)=><div key={ticket.id}><span>{i+1}</span>{ticket.number} · {ticket.city.split(",")[0]}</div>)}</div></div><div className="api-note"><Sparkles size={16}/>Chamados sem coordenadas permanecem no final para revisão manual.</div><div className="modal-actions"><button className="btn secondary" onClick={close}>Cancelar</button><button className="btn primary" onClick={apply}><Check size={17}/>Aplicar ao rascunho</button></div></div></div>}

function StableRouteMap({flash,items}:{flash:(s:string)=>void;items:Ticket[]}){
 const {technicians,branches,analysts,routeStartPoints,updateTicket,cancelTicket,deleteTicket}=useAppData();const activeTechs=technicians.filter(item=>item.active);const [selected,setSelected]=useState<string|null>(activeTechs[0]?.name||null);const [day,setDay]=useState(new Date().toISOString().slice(0,10));const [editing,setEditing]=useState<Ticket|null>(null);const [analyst,setAnalyst]=useState("");const [city,setCity]=useState("");const [urgency,setUrgency]=useState("");
 const dayItems=items.filter(ticket=>ticket.date===day&&ticket.tech&&ticket.planningStatus!=="nao_planejado"&&ticket.status!=="Cancelado"&&(!analyst||ticketAnalyst(ticket)===analyst)&&(!city||ticket.city.startsWith(city))&&(!urgency||ticket.urgency===urgency)).sort((a,b)=>(a.tech||"").localeCompare(b.tech||"")||(a.routeOrder||Number.MAX_SAFE_INTEGER)-(b.routeOrder||Number.MAX_SAFE_INTEGER));const visibleTechs=selected?activeTechs.filter(item=>item.name===selected):activeTechs;
 const getPoint=(ticket:Ticket)=>{const branch=resolveTicketBranch(ticket,branches);return {latitude:isValidCoordinate(ticket.latitude,ticket.longitude)?ticket.latitude:branch?.latitude??null,longitude:isValidCoordinate(ticket.latitude,ticket.longitude)?ticket.longitude:branch?.longitude??null,branch}};
 const routes=visibleTechs.map(technician=>{const saved=routeStartPoints[`${technician.name}-${day}`];const start=saved||{description:technician.address,latitude:technician.latitude??null,longitude:technician.longitude??null};const routeTickets=dayItems.filter(ticket=>ticket.tech===technician.name).sort((a,b)=>(a.routeOrder||Number.MAX_SAFE_INTEGER)-(b.routeOrder||Number.MAX_SAFE_INTEGER));const metadata=routeTickets[0];const stops=routeTickets.map((ticket,index)=>{const point=getPoint(ticket);return isValidCoordinate(point.latitude,point.longitude)?{id:ticket.id,number:ticket.number,branch:point.branch?.nome||ticket.branch||"Filial não associada",city:point.branch?`${point.branch.cidade}, ${point.branch.uf}`:ticket.city,address:point.branch?.endereco||ticket.address,technician:technician.name,status:ticket.status,order:ticket.routeOrder||index+1,urgency:ticket.urgency,analyst:ticketAnalyst(ticket),latitude:point.latitude!,longitude:point.longitude!}:null}).filter((stop):stop is NonNullable<typeof stop>=>stop!==null);return {technician:technician.name,color:technician.color,start,stops,geometry:metadata?.routeGeometry,source:metadata?.routeSource,distanceKm:metadata?.roadDistanceKm,durationMinutes:metadata?.roadDurationMinutes}});
 const routeDistances=routes.map(route=>route.distanceKm??calculateRouteDistance(getValidRoutePoints([...(route.start?[route.start]:[]),...route.stops]))).filter((value):value is number=>value!==null);const distance=routeDistances.length?routeDistances.reduce((sum,value)=>sum+value,0):null;const routeDurations=routes.map(route=>route.durationMinutes).filter((value):value is number=>typeof value==="number"&&Number.isFinite(value));const duration=routeDurations.length===routes.filter(route=>route.stops.length).length&&routeDurations.length?routeDurations.reduce((sum,value)=>sum+value,0):distance===null?null:Math.round(distance);const assigned=selected?dayItems.filter(ticket=>ticket.tech===selected):dayItems;const missing=assigned.filter(ticket=>{const point=getPoint(ticket);return !isValidCoordinate(point.latitude,point.longitude)});const selectedTech=selected?activeTechs.find(item=>item.name===selected):undefined;const selectedStart=selectedTech?(routeStartPoints[`${selectedTech.name}-${day}`]||{latitude:selectedTech.latitude,longitude:selectedTech.longitude}):undefined;const mapSource=routes.some(route=>route.source==="tomtom")?"TomTom":"Haversine / linha reta";
 const clearFilters=()=>{setAnalyst("");setCity("");setUrgency("")};
 return <><PageHead title="Mapa de rotas" sub="Rotas confirmadas e rascunhos, ordenados pela sequência planejada."><input className="select" type="date" value={day} onChange={event=>setDay(event.target.value)}/><button className="btn primary" onClick={()=>{setSelected(null);flash("Exibindo todas as rotas do dia")}}><Route size={17}/>Ver todas as rotas</button></PageHead><div className="toolbar map-filters"><select className="select" value={analyst} onChange={event=>setAnalyst(event.target.value)}><option value="">Todos os analistas</option>{analysts.map(item=><option key={item}>{item}</option>)}</select><select className="select" value={city} onChange={event=>setCity(event.target.value)}><option value="">Todas as cidades</option>{cidadesFiliais.map(item=><option key={item}>{item}</option>)}</select><select className="select" value={urgency} onChange={event=>setUrgency(event.target.value)}><option value="">Todas as urgências</option>{["Alta","Média","Baixa"].map(item=><option key={item}>{item}</option>)}</select><button className="btn secondary" onClick={clearFilters}>Limpar filtros</button><span className="result-count">{dayItems.length} chamados</span></div><div className="simulation-note"><Sparkles size={15}/>Linha aproximada entre pontos. Ainda não considera ruas/rodovias.</div><div className="map-layout"><div className="map-side panel"><h3>Rotas do dia</h3><p>{activeTechs.length} técnicos ativos · {dayItems.length} chamados</p>{activeTechs.map(item=><button className={`map-tech ${selected===item.name?"selected":""}`} key={item.id} onClick={()=>setSelected(item.name)}><div className="map-tech-top"><Avatar name={item.name}/><div><b>{item.name}</b><span>{dayItems.filter(ticket=>ticket.tech===item.name).length} chamados</span></div><i style={{background:item.color}}/></div></button>)}<div className="map-detail"><b>{selected||"Todas as rotas"} · {new Date(`${day}T12:00`).toLocaleDateString("pt-BR")}</b>{selectedTech&&<span><MapPin size={13}/>{routeStartPoints[`${selectedTech.name}-${day}`]?.address||selectedTech.address||"Origem sem endereço"}</span>}{selectedTech&&!isValidCoordinate(selectedStart?.latitude,selectedStart?.longitude)&&<span className="warning-text"><AlertTriangle size={13}/>Ponto de saída sem coordenada.</span>}<span><TicketCheck size={13}/>{assigned.length} chamados</span><span><Building2 size={13}/>{Array.from(new Set(assigned.map(ticket=>ticket.city))).join(", ")||"Sem cidades planejadas"}</span><span><Route size={13}/>{distance===null?"Distância não calculada":`${distance.toFixed(1)} km · ${Math.round(distance)} min`}</span>{!selected&&distance!==null&&<span>Somatório independente das rotas dos técnicos.</span>}{missing.length>0&&<b>Chamados sem coordenadas</b>}{missing.map(ticket=><span key={ticket.id} className="missing-stop">{ticket.number} · {ticket.branch}</span>)}{assigned.map(ticket=><button className="map-ticket-edit" key={ticket.id} onClick={()=>setEditing({...ticket})}><Pencil size={12}/>{ticket.number} · Editar</button>)}</div></div><LeafletRouteMap routes={routes}/></div>{editing&&<TicketModal ticket={editing} onChange={setEditing} onCancel={()=>setEditing(null)} onSave={()=>{updateTicket(editing);setEditing(null);flash("Chamado atualizado no mapa e nas demais telas")}} onCancelTicket={()=>{if(window.confirm("Cancelar este chamado e removê-lo do planejamento?")){cancelTicket(editing.id);setEditing(null);flash("Chamado cancelado")}}} onDelete={()=>{if(window.confirm("Tem certeza que deseja excluir este chamado? Essa ação não pode ser desfeita.")){deleteTicket(editing.id);setEditing(null);flash("Chamado excluído")}}} onOfficialComplete={()=>{updateTicket({...editing,status:"Concluído"});setEditing(null);flash("Chamado concluído oficialmente")}}/>}</>;
}

function RouteMap({flash,items}:{flash:(s:string)=>void;items:Ticket[]}){
 const {technicians:techs,branches:filiaisBase,analysts,routeStartPoints,updateTicket,cancelTicket,deleteTicket}=useAppData();
 const [selected,setSelected]=useState<number|null>(0); const [day,setDay]=useState(new Date().toISOString().slice(0,10)); const [editing,setEditing]=useState<Ticket|null>(null);const [analystFilter,setAnalystFilter]=useState("");const [cityFilter,setCityFilter]=useState("");const [urgencyFilter,setUrgencyFilter]=useState("");const tech=selected===null?null:techs[selected];
 const dayItems=items.filter(t=>t.date===day&&t.tech&&t.planningStatus&&t.planningStatus!=="nao_planejado"&&t.status!=="Cancelado"&&(!analystFilter||ticketAnalyst(t)===analystFilter)&&(!cityFilter||t.city.startsWith(cityFilter))&&(!urgencyFilter||t.urgency===urgencyFilter)); const assigned=tech?dayItems.filter(t=>t.tech===tech.name):dayItems;
 const visibleTechs=tech?[tech]:techs;
 const routes=visibleTechs.map(t=>{const saved=routeStartPoints[`${t.name}-${day}`];const start=saved||{description:AGRICOPEL_BASE.description,address:t.address,latitude:isValidCoordinate(t.latitude,t.longitude)?t.latitude:AGRICOPEL_BASE.latitude,longitude:isValidCoordinate(t.latitude,t.longitude)?t.longitude:AGRICOPEL_BASE.longitude};return {technician:t.name,color:t.color,start,stops:dayItems.filter(x=>x.tech===t.name).map((x,index)=>{const f=resolveTicketBranch(x,filiaisBase);return isValidCoordinate(x.latitude??f?.latitude,x.longitude??f?.longitude)?{id:x.id??`stop-${index}`,number:x.number||"Chamado sem número",branch:f?.nome||x.branch||"Filial não associada",city:f?`${f.cidade}, ${f.uf}`:x.city||"Cidade não informada",address:f?.endereco||x.address||"Endereço não informado",technician:t.name,status:x.status||"Não informado",technicianStatus:technicianStatusKey(x.technicianStatus),order:x.routeOrder||index+1,urgency:x.urgency||"Não informada",latitude:(x.latitude??f!.latitude)!,longitude:(x.longitude??f!.longitude)!}:null}).filter((stop):stop is NonNullable<typeof stop>=>stop!==null)}});
 const selectedStart=tech?(routeStartPoints[`${tech.name}-${day}`]||{latitude:isValidCoordinate(tech.latitude,tech.longitude)?tech.latitude:AGRICOPEL_BASE.latitude,longitude:isValidCoordinate(tech.latitude,tech.longitude)?tech.longitude:AGRICOPEL_BASE.longitude}):undefined;const points=getValidRoutePoints([...(selectedStart?[selectedStart]:[]),...assigned.map(x=>{const branch=resolveTicketBranch(x,filiaisBase);return {latitude:x.latitude??branch?.latitude,longitude:x.longitude??branch?.longitude}})]);
 const distance=calculateRouteDistance(points); const missing=assigned.filter(x=>{const f=filiaisBase.find(b=>b.numeroFilial===x.branchNumber);return !isValidCoordinate(x.latitude??f?.latitude,x.longitude??f?.longitude)});
 return <><PageHead title="Mapa de rotas" sub="Visualize a distribuição dos atendimentos planejados."><input className="select" type="date" value={day} onChange={e=>setDay(e.target.value)}/><button className="btn primary" onClick={()=>{setSelected(null);flash("Exibindo todas as rotas do dia")}}><Route size={17}/>Ver todas as rotas</button></PageHead><div className="simulation-note"><Sparkles size={15}/>Linha aproximada entre pontos. Ainda não considera ruas/rodovias.</div><div className="map-layout"><div className="map-side panel"><h3>Rotas do dia</h3><p>{techs.length} técnicos · {dayItems.length} chamados</p>{techs.map((t,i)=><button className={`map-tech ${selected===i?"selected":""}`} key={t.name} onClick={()=>setSelected(i)}><div className="map-tech-top"><Avatar name={t.name}/><div><b>{t.name}</b><span>{dayItems.filter(x=>x.tech===t.name).length} chamados</span></div><i style={{background:t.color}}/></div></button>)}<div className="map-detail"><b>{tech?.name||"Todas as rotas"} · {new Date(`${day}T12:00`).toLocaleDateString("pt-BR")}</b>{tech&&<span><MapPin size={13}/>{(routeStartPoints[`${tech.name}-${day}`]?.address||tech.address)||"Origem sem endereço"}</span>}{tech&&!isValidCoordinate(selectedStart?.latitude,selectedStart?.longitude)&&<span className="warning-text"><AlertTriangle size={13}/>Ponto de saída sem coordenada.</span>}<span><TicketCheck size={13}/>{assigned.length} chamados do dia</span><span><Building2 size={13}/>{Array.from(new Set(assigned.map(t=>t.city))).join(", ")||"Sem cidades planejadas"}</span><span><Route size={13}/>{distance===null?"Distância parcial/não calculada":`${distance.toFixed(1)} km · ${Math.round(distance)} min`}</span>{missing.length>0&&<b>Chamados sem coordenadas</b>}<span className="warning-text"><AlertTriangle size={13}/>{missing.length} filiais sem coordenadas</span>{missing.map(x=><span key={x.id} className="missing-stop">Sem coordenadas: {x.number} · {x.branch}</span>)}{assigned.map(ticket=><button className="map-ticket-edit" key={ticket.id} onClick={()=>setEditing({...ticket})}><Pencil size={12}/>{ticket.number} · Editar</button>)}</div></div><LeafletRouteMap routes={routes}/></div>{editing&&<TicketModal ticket={editing} onChange={setEditing} onCancel={()=>setEditing(null)} onSave={()=>{updateTicket(editing);setEditing(null);flash("Chamado atualizado no mapa e nas demais telas")}} onCancelTicket={()=>{cancelTicket(editing.id);setEditing(null);flash("Chamado cancelado")}} onDelete={()=>{if(window.confirm("Tem certeza que deseja excluir este chamado? Essa ação não pode ser desfeita.")){deleteTicket(editing.id);setEditing(null);flash("Chamado excluído")}}} onOfficialComplete={()=>{updateTicket({...editing,status:"Concluído"});setEditing(null);flash("Chamado concluído oficialmente")}}/>}</>;
}

const emptyFilial:Filial={id:0,numeroFilial:"",nome:"",cidade:"",uf:"SC",endereco:"",bairro:"",cep:"",cnpj:"",inscricaoEstadual:"",telefone:"",status:"ativo",latitude:null,longitude:null,geocodeStatus:"pendente",statusDados:"incompleto",fonteCoordenada:"",linkMapa:"",observacoes:""};
function Branches({flash}:{flash:(s:string)=>void}){
 const {branches:items,updateBranch}=useAppData();
 const [editing,setEditing]=useState<Filial|null>(null);
 const [isNew,setIsNew]=useState(false);
 const [query,setQuery]=useState(""); const [city,setCity]=useState(""); const [status,setStatus]=useState(""); const [issue,setIssue]=useState("");
 const cities=useMemo(()=>Array.from(new Set(items.map(f=>f.cidade).filter(Boolean))).sort(),[items]);
 const shown=items.filter(f=>(!query||`${f.numeroFilial} ${f.nome} ${f.cidade}`.toLowerCase().includes(query.toLowerCase()))&&(!city||f.cidade===city)&&(!status||f.status===status)&&(!issue||(issue==="coords"?f.latitude===null||f.longitude===null:f.statusDados==="incompleto")));
 const save=()=>{if(!editing||!editing.nome.trim())return;const numeroFilial=branchNumberFromCnpj(editing.cnpj)??editing.numeroFilial;if(items.some(item=>item.id!==editing.id&&item.numeroFilial===numeroFilial)){flash("Já existe uma filial com este número");return}if(editing.cnpj&&items.some(item=>item.id!==editing.id&&normalizeText(item.cnpj)===normalizeText(editing.cnpj))){flash("Já existe uma filial com este CNPJ");return}const hasCoords=isValidCoordinate(editing.latitude,editing.longitude);const clean:Filial={...editing,numeroFilial,statusDados:(!editing.cidade||!editing.endereco||!editing.cep)?"incompleto":hasCoords?"ok":"sem_coordenadas",geocodeStatus:hasCoords?"preenchida":"pendente"};updateBranch(clean,isNew);setEditing(null);flash(isNew?"Nova filial cadastrada com sucesso":"Filial atualizada com sucesso")};const exportBranches=()=>downloadCsv("filiais-rotasmart.csv",[["Número","Nome","CNPJ","Cidade","UF","Endereço","CEP","Latitude","Longitude","Status"],...shown.map(item=>[item.numeroFilial,item.nome,item.cnpj,item.cidade,item.uf,item.endereco,item.cep,item.latitude,item.longitude,item.status])]);
 return <><PageHead title="Filiais e postos" sub="Base real extraída do documento Agrícola."><button className="btn secondary" onClick={exportBranches}><Download size={17}/>Exportar CSV</button><button className="btn primary" onClick={()=>{setEditing({...emptyFilial});setIsNew(true)}}><Plus size={17}/>Nova filial</button></PageHead>
 <div className="toolbar branch-filters"><div className="searchbox"><Search size={17}/><input value={query} onChange={e=>setQuery(e.target.value)} placeholder="Buscar filial..."/></div><select className="select" value={city} onChange={e=>setCity(e.target.value)}><option value="">Todas as cidades</option>{cities.map(c=><option key={c}>{c}</option>)}</select><select className="select" value={status} onChange={e=>setStatus(e.target.value)}><option value="">Todos os status</option><option value="ativo">Ativos</option><option value="desativado">Desativados</option></select><select className="select" value={issue} onChange={e=>setIssue(e.target.value)}><option value="">Todos os dados</option><option value="incomplete">Dados incompletos</option><option value="coords">Sem coordenadas</option></select><span className="result-count">{shown.length} filiais</span></div>
 <div className="panel table-panel"><table><thead><tr><th>Nº FILIAL</th><th>NOME</th><th>LOCALIZAÇÃO</th><th>ENDEREÇO</th><th>STATUS / DADOS</th><th></th></tr></thead><tbody>{shown.map(f=><tr key={f.id}><td><b>{f.numeroFilial}</b></td><td><b>{f.nome}</b><small>{f.cnpj}</small></td><td>{f.cidade||"Não informada"}<small>{f.uf}</small></td><td>{f.endereco||"Não informado"}<small>{f.cep}</small></td><td><span className={`active-pill ${f.status==="ativo"?"":"off"}`}><i/>{f.status==="ativo"?"Ativo":"Desativado"}</span>{f.geocodeStatus==="pendente"&&<span className="data-warning">Sem coordenadas</span>}{f.statusDados==="incompleto"&&<span className="data-warning danger">Dados incompletos</span>}</td><td><button className="icon-button" onClick={()=>{setEditing({...f});setIsNew(false)}}><MoreHorizontal/></button></td></tr>)}</tbody></table></div>
 {editing&&<FilialModal filial={editing} isNew={isNew} onChange={setEditing} onCancel={()=>setEditing(null)} onSave={save}/>}</>;
}

function FilialModal({filial,isNew,onChange,onCancel,onSave}:{filial:Filial;isNew:boolean;onChange:(f:Filial)=>void;onCancel:()=>void;onSave:()=>void}){
 const set=(key:keyof Filial,value:any)=>onChange({...filial,[key]:value});
 return <div className="modal-bg tech-modal-bg"><div className="tech-modal branch-modal"><div className="tech-modal-head"><div><span className="eyebrow">{isNew?"NOVO CADASTRO":"EDITAR FILIAL"}</span><h2>{isNew?"Nova filial":filial.nome}</h2><p>Dados operacionais da base de filiais e postos.</p></div><button onClick={onCancel}><X/></button></div><div className="tech-form">
 <label className="field"><span>Número da filial</span><input value={branchNumberFromCnpj(filial.cnpj)??filial.numeroFilial} readOnly title="Calculado automaticamente pelo CNPJ"/></label><label className="field"><span>Status</span><select value={filial.status} onChange={e=>set("status",e.target.value)}><option value="ativo">Ativo</option><option value="desativado">Desativado</option></select></label>
 <label className="field span-2"><span>Nome *</span><input value={filial.nome} onChange={e=>set("nome",e.target.value)}/></label><label className="field"><span>Cidade</span><input list="real-cities" value={filial.cidade} onChange={e=>set("cidade",e.target.value)}/><datalist id="real-cities">{cidadesFiliais.map(c=><option key={c}>{c}</option>)}</datalist></label><label className="field"><span>UF</span><input maxLength={2} value={filial.uf} onChange={e=>set("uf",e.target.value.toUpperCase())}/></label>
 <label className="field span-2"><span>Endereço</span><input value={filial.endereco} onChange={e=>set("endereco",e.target.value)}/></label><label className="field"><span>CEP</span><input value={filial.cep} onChange={e=>set("cep",e.target.value)}/></label><label className="field"><span>Telefone</span><input value={filial.telefone} onChange={e=>set("telefone",e.target.value)}/></label><label className="field span-2"><span>CNPJ</span><input value={filial.cnpj} onChange={e=>{const cnpj=e.target.value;onChange({...filial,cnpj,numeroFilial:branchNumberFromCnpj(cnpj)??filial.numeroFilial})}}/><small>O número da filial é calculado pelo estabelecimento do CNPJ menos 1.</small></label>
 <label className="field"><span>Latitude</span><input type="number" step="any" value={filial.latitude??""} onChange={e=>set("latitude",e.target.value===""?null:Number(e.target.value))}/></label><label className="field"><span>Longitude</span><input type="number" step="any" value={filial.longitude??""} onChange={e=>set("longitude",e.target.value===""?null:Number(e.target.value))}/></label><label className="field span-2"><span>Observações</span><textarea value={filial.observacoes} onChange={e=>set("observacoes",e.target.value)}/></label></div><div className="tech-modal-actions"><button className="btn secondary" onClick={onCancel}>Cancelar</button><button className="btn primary" disabled={!filial.nome.trim()} onClick={onSave}><Check size={17}/>Salvar alterações</button></div></div></div>;
}
function DataToolbar({count}:{count:string}){return <div className="toolbar"><div className="searchbox"><Search size={17}/><input placeholder="Buscar por nome, cidade ou número..."/></div><button className="select"><Filter size={16}/>Todos os status<ChevronDown size={16}/></button><span className="result-count">{count}</span></div>}
const emptyTechnician: Technician = {id:0,name:"",initials:"",color:"#2563eb",city:"",address:"",startTime:"08:00",endTime:"17:30",active:true,notes:"",latitude:null,longitude:null};

function Technicians({flash}:{flash:(s:string)=>void}){
 const {technicians:items,updateTechnician}=useAppData();
 const [editing,setEditing]=useState<Technician|null>(null);
 const [isNew,setIsNew]=useState(false);
 const openNew=()=>{setEditing({...emptyTechnician});setIsNew(true)};
 const openEdit=(tech:Technician)=>{setEditing({...tech});setIsNew(false)};
 const save=()=>{
  if(!editing||!editing.name.trim())return;
  if(items.some(item=>item.id!==editing.id&&normalizeText(item.name)===normalizeText(editing.name))){flash("Já existe um técnico com este nome");return}
  const clean={...editing,initials:editing.initials.trim().toUpperCase()||editing.name.slice(0,2).toUpperCase()};updateTechnician(clean,isNew);flash(isNew?"Novo técnico cadastrado com sucesso":"Alterações salvas com sucesso");
  setEditing(null);
 };
 return <><PageHead title="Técnicos" sub="Configure a equipe, jornadas e pontos de saída."><button className="btn primary" onClick={openNew}><Plus size={17}/>Novo técnico</button></PageHead>
 <div className="tech-cards">{items.map(t=><div className="panel tech-detail" key={t.id}><div className="tech-card-head"><div className="big-avatar" style={{background:t.color}}>{t.initials}</div><div><h3>{t.name}</h3><span className={`active-pill ${t.active?"":"off"}`}><i/>{t.active?"Ativo":"Inativo"}</span></div><button aria-label={`Editar ${t.name}`} onClick={()=>openEdit(t)}><MoreHorizontal/></button></div><div className="tech-data"><p><MapPin/><span>Cidade base<b>{t.city||"Não informada"}</b></span></p><p><Route/><span>Ponto de saída padrão<b>{t.address||"Não informado"}</b></span></p><p><Clock3/><span>Jornada padrão<b>{t.startTime} — {t.endTime}</b></span></p></div><div className="map-color"><span>Cor no mapa</span><i style={{background:t.color}}/><code>{t.color}</code></div><button className="edit-tech" onClick={()=>openEdit(t)}>Editar técnico</button></div>)}</div>
 {editing&&<TechnicianModal technician={editing} isNew={isNew} onChange={setEditing} onCancel={()=>setEditing(null)} onSave={save}/>}</>;
}

function TechnicianModal({technician,isNew,onChange,onCancel,onSave}:{technician:Technician;isNew:boolean;onChange:(t:Technician)=>void;onCancel:()=>void;onSave:()=>void}){
 const update=<K extends keyof Technician>(key:K,value:Technician[K])=>onChange({...technician,[key]:value});
 return <div className="modal-bg tech-modal-bg" role="dialog" aria-modal="true" aria-labelledby="tech-modal-title"><div className="tech-modal">
  <div className="tech-modal-head"><div><span className="eyebrow">{isNew?"NOVO CADASTRO":"EDITAR CADASTRO"}</span><h2 id="tech-modal-title">{isNew?"Novo técnico":`Editar ${technician.name}`}</h2><p>Configure os dados operacionais e a identificação no mapa.</p></div><button onClick={onCancel} aria-label="Fechar"><X/></button></div>
  <div className="tech-form">
   <label className="field span-2"><span>Nome *</span><input autoFocus value={technician.name} onChange={e=>update("name",e.target.value)} placeholder="Nome completo"/></label>
   <label className="field"><span>Sigla / iniciais</span><input maxLength={3} value={technician.initials} onChange={e=>update("initials",e.target.value.toUpperCase())} placeholder="Ex.: WA"/></label>
   <label className="field"><span>Status</span><select value={technician.active?"active":"inactive"} onChange={e=>update("active",e.target.value==="active")}><option value="active">Ativo</option><option value="inactive">Inativo</option></select></label>
   <label className="field span-2"><span>Cidade base</span><input value={technician.city} onChange={e=>update("city",e.target.value)} placeholder="Cidade, UF"/></label>
   <label className="field span-2"><span>Ponto de saída padrão</span><input value={technician.address} onChange={e=>update("address",e.target.value)} placeholder="Endereço completo"/></label>
   <label className="field"><span>Latitude do ponto de saída</span><input type="number" step="any" value={technician.latitude??""} onChange={e=>update("latitude",e.target.value===""?null:Number(e.target.value))}/></label>
   <label className="field"><span>Longitude do ponto de saída</span><input type="number" step="any" value={technician.longitude??""} onChange={e=>update("longitude",e.target.value===""?null:Number(e.target.value))}/></label>
   <label className="field"><span>Horário inicial padrão</span><input type="time" value={technician.startTime} onChange={e=>update("startTime",e.target.value)}/></label>
   <label className="field"><span>Horário final padrão</span><input type="time" value={technician.endTime} onChange={e=>update("endTime",e.target.value)}/></label>
   <label className="field span-2"><span>Cor no mapa</span><div className="color-field"><input type="color" value={technician.color} onChange={e=>update("color",e.target.value)}/><input value={technician.color} onChange={e=>update("color",e.target.value)} maxLength={7}/><i style={{background:technician.color}}/></div></label>
   <label className="field span-2"><span>Observações</span><textarea rows={3} value={technician.notes} onChange={e=>update("notes",e.target.value)} placeholder="Informações internas sobre disponibilidade, região ou especialidade."/></label>
  </div>
  <div className="tech-modal-actions"><button className="btn secondary" onClick={onCancel}>Cancelar</button><button className="btn primary" disabled={!technician.name.trim()} onClick={onSave}><Check size={17}/>Salvar alterações</button></div>
 </div></div>;
}
